#include <stdint.h>
int64_t putchar(char ch) {
    register uint64_t a0 asm("a0") = ch;  // 字符
    register uint64_t a7 asm("a7") = 0x1; // SBI_CONSOLE_PUTCHAR
    asm volatile("ecall"                  // 发起SBI调用
                 : "+r"(a0)
                 : "r"(a7)
                 : "memory");
    return (int64_t)a0;                   // 返回 0 表示成功，负值表示失败
}
